package com.recettealarm.app;import android.app.*;import android.content.*;import android.view.*;import android.widget.*;import android.graphics.Color;import android.graphics.Typeface;import android.graphics.drawable.*;
public class UI{static int brown=Color.rgb(169,84,45),cream=Color.rgb(255,250,244);static TextView tv(Context c,String t,int sp,int style){TextView v=new TextView(c);v.setText(t);v.setTextSize(sp);v.setTypeface(Typeface.DEFAULT,style);v.setTextColor(Color.rgb(45,39,35));v.setPadding(20,12,20,8);return v;}static Button btn(Context c,String t){Button b=new Button(c);b.setText(t);b.setTextColor(Color.WHITE);b.setTextSize(16);GradientDrawable g=new GradientDrawable();g.setColor(brown);g.setCornerRadius(40);b.setBackground(g);return b;}static EditText input(Context c,String h){EditText e=new EditText(c);e.setHint(h);e.setSingleLine(false);e.setPadding(24,10,24,10);return e;}static LinearLayout root(Activity a){LinearLayout l=new LinearLayout(a);l.setOrientation(LinearLayout.VERTICAL);l.setPadding(28,28,28,28);l.setBackgroundColor(cream);a.setContentView(new ScrollView(a){{addView(l);}});return l;}static TextView card(Context c,String t){TextView v=tv(c,t,18,Typeface.BOLD);GradientDrawable g=new GradientDrawable();g.setColor(Color.WHITE);g.setCornerRadius(35);g.setStroke(1,0xffeadfd6);v.setBackground(g);v.setPadding(35,25,35,25);return v;}static void toast(Context c,String s){Toast.makeText(c,s,Toast.LENGTH_SHORT).show();}}
